#include<iostream>#include<vector>#include<set>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<ll>a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        ll ans=0;        for(int i=1;i<=60;i++){            ll k= 1LL << i ;            set<ll>d;            for(int i=0;i<n;i++){                d.insert(a[i]%k);            }            if(d.size()==2){                ans=k;                break;            }        }        cout<<ans<<"\n";    }}